import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class XSSFixedServlet extends HttpServlet {
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Properly handling user input by sanitizing and escaping it before printing to the response
        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<head><title>XSS Fixed Page</title></head>");
        out.println("<body>");
        out.println("<h1>User Input: " + encodeHtml(userInput) + "</h1>"); // Properly sanitized user input
        out.println("</body></html>");
    }

    private String encodeHtml(String input) {
        return input != null ? org.owasp.esapi.codecs.HTMLEntityCodec.getInstance().encode(input) : "";
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
